/**
 * @file use-chat.ts
 * @description Hook to access the ChatService from the authenticated UserDialer.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { ChatService } from '@dial-wtf/client';
import { UserDialerContext } from '../context';

/**
 * Access the chat service for E2EE DMs and group messaging.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * const chat = useChat();
 * await chat.send({ to: '0x...', content: 'Hello!' });
 * ```
 */
export function useChat(): ChatService {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useChat must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  if (!ctx.userDialer) {
    throw new Error(
      'useChat requires an authenticated session. ' +
      'Call login() via useAuth() before using this hook.',
    );
  }

  return ctx.userDialer.chat;
}
