/**
 * @file use-voicemail.ts
 * @description Hook to access the VoicemailService from the authenticated UserDialer.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { VoicemailService } from '@dial-wtf/client';
import { UserDialerContext } from '../context';

/**
 * Access the voicemail service for managing voicemails.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * const voicemail = useVoicemail();
 * const messages = await voicemail.getAll();
 * ```
 */
export function useVoicemail(): VoicemailService {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useVoicemail must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  if (!ctx.userDialer) {
    throw new Error(
      'useVoicemail requires an authenticated session. ' +
      'Call login() via useAuth() before using this hook.',
    );
  }

  return ctx.userDialer.voicemail;
}
