/**
 * @file context.ts
 * @description React contexts for DialClient and UserDialer instances.
 * @layer React Context
 */

'use client';

import { createContext } from 'react';
import type { DialClient, UserDialer } from '@dial-wtf/client';

/**
 * Context providing the DialClient instance.
 *
 * Set by DialProvider — consumers access it via useDialClient().
 */
export const DialClientContext = createContext<DialClient | null>(null);
DialClientContext.displayName = 'DialClientContext';

/**
 * Context providing the authenticated UserDialer instance.
 *
 * Null until the user calls login() / loginWithWallet() / loginWithSolana().
 * Cleared on logout().
 */
export const UserDialerContext = createContext<{
  userDialer: UserDialer | null;
  setUserDialer: (ud: UserDialer | null) => void;
} | null>(null);
UserDialerContext.displayName = 'UserDialerContext';
