/**
 * @file use-contacts.ts
 * @description Hook to access the ContactsBook from the authenticated UserDialer.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { ContactsBook } from '@dial-wtf/client';
import { UserDialerContext } from '../context';

/**
 * Access the contacts book for managing user contacts.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * const contacts = useContacts();
 * await contacts.add({ walletAddress: '0x...' });
 * const all = await contacts.getAll();
 * ```
 */
export function useContacts(): ContactsBook {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useContacts must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  if (!ctx.userDialer) {
    throw new Error(
      'useContacts requires an authenticated session. ' +
      'Call login() via useAuth() before using this hook.',
    );
  }

  return ctx.userDialer.contacts;
}
