/**
 * @file use-calls.ts
 * @description Hook to access the CallsService from the authenticated UserDialer.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { CallsService } from '@dial-wtf/client';
import { UserDialerContext } from '../context';

/**
 * Access the calls service for wallet-to-wallet audio/video calling.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * const calls = useCalls();
 * const call = await calls.start({ to: '0x...', type: 'video' });
 * ```
 */
export function useCalls(): CallsService {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useCalls must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  if (!ctx.userDialer) {
    throw new Error(
      'useCalls requires an authenticated session. ' +
      'Call login() via useAuth() before using this hook.',
    );
  }

  return ctx.userDialer.calls;
}
