/**
 * @file provider.tsx
 * @description DialProvider — top-level context provider for the Dial SDK.
 * @layer React Context
 */

'use client';

import React, { useMemo, useState } from 'react';
import type { DialClientConfig } from '@dial-wtf/core';
import { DialClient } from '@dial-wtf/client';
import type { UserDialer } from '@dial-wtf/client';
import { DialClientContext, UserDialerContext } from './context';

/**
 * Props for the DialProvider component.
 */
export interface DialProviderProps extends DialClientConfig {
  children: React.ReactNode;
}

/**
 * DialProvider — wraps your app with Dial SDK context.
 *
 * Creates a DialClient from the provided config and makes it available
 * to all child components via useDialClient() and related hooks.
 *
 * @example
 * ```tsx
 * import { DialProvider } from '@dial-wtf/react';
 *
 * function App() {
 *   return (
 *     <DialProvider apiKey="pk_live_..." network="alpha">
 *       <MyApp />
 *     </DialProvider>
 *   );
 * }
 * ```
 */
export function DialProvider({
  children,
  ...config
}: DialProviderProps): React.JSX.Element {
  const client = useMemo(
    () => new DialClient(config),
    // Stable on the values that actually matter for client construction
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [config.apiKey, config.network, config.baseUrl, config.timeout, config.debug],
  );

  const [userDialer, setUserDialer] = useState<UserDialer | null>(null);

  const userDialerValue = useMemo(
    () => ({ userDialer, setUserDialer }),
    [userDialer],
  );

  return (
    <DialClientContext.Provider value={client}>
      <UserDialerContext.Provider value={userDialerValue}>
        {children}
      </UserDialerContext.Provider>
    </DialClientContext.Provider>
  );
}
