/**
 * @file use-dial-event.ts
 * @description Hook to subscribe to UserDialer events with automatic cleanup.
 * @layer React Hooks
 */

'use client';

import { useContext, useEffect, useRef } from 'react';
import type { DialEventType, EventListener } from '@dial-wtf/core';
import { UserDialerContext } from '../context';

/**
 * Subscribe to events on the authenticated UserDialer.
 *
 * The subscription is created when the component mounts (and the user is
 * authenticated) and cleaned up on unmount or when the event/callback changes.
 *
 * Tip: stabilise the callback with useCallback or pass a ref to avoid
 * unnecessary resubscriptions.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * useDialEvent('call:incoming', useCallback((call) => {
 *   console.log('Incoming call from:', call.from);
 * }, []));
 * ```
 */
export function useDialEvent<T extends DialEventType>(
  event: T,
  callback: EventListener<T>,
): void {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useDialEvent must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  // Keep a stable ref to the latest callback so we don't resubscribe on
  // every render when the consumer forgets to memoise.
  const callbackRef = useRef(callback);
  callbackRef.current = callback;

  const userDialer = ctx.userDialer;

  useEffect(() => {
    if (!userDialer) return;

    const handler: EventListener<T> = (payload) => {
      callbackRef.current(payload);
    };

    userDialer.on(event, handler);

    return () => {
      userDialer.off(event, handler);
    };
  }, [userDialer, event]);
}
