/**
 * @file use-dial-client.ts
 * @description Hook to access the DialClient instance from context.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { DialClient } from '@dial-wtf/client';
import { DialClientContext } from '../context';

/**
 * Access the DialClient instance from the nearest DialProvider.
 *
 * @throws Error if used outside of a DialProvider.
 *
 * @example
 * ```tsx
 * const dial = useDialClient();
 * const rooms = await dial.partyLines.getActive();
 * ```
 */
export function useDialClient(): DialClient {
  const client = useContext(DialClientContext);
  if (!client) {
    throw new Error(
      'useDialClient must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }
  return client;
}
