/**
 * @file use-profile.ts
 * @description Hook to access the ProfileService from the authenticated UserDialer.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { ProfileService } from '@dial-wtf/client';
import { UserDialerContext } from '../context';

/**
 * Access the profile service for managing user profiles.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * const profile = useProfile();
 * const me = await profile.get();
 * ```
 */
export function useProfile(): ProfileService {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useProfile must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  if (!ctx.userDialer) {
    throw new Error(
      'useProfile requires an authenticated session. ' +
      'Call login() via useAuth() before using this hook.',
    );
  }

  return ctx.userDialer.profile;
}
