/**
 * @file use-auth.ts
 * @description Authentication hook — login, logout, and session state.
 * @layer React Hooks
 */

'use client';

import { useCallback, useContext, useMemo, useState } from 'react';
import type { AuthCredentials, SessionData } from '@dial-wtf/core';
import type { UserDialer } from '@dial-wtf/client';
import { DialClientContext, UserDialerContext } from '../context';

/**
 * Return type for the useAuth hook.
 */
export interface UseAuthReturn {
  /** Authenticate with SIWE / SIWS credentials and create a UserDialer session. */
  login: (credentials: AuthCredentials) => Promise<UserDialer>;
  /** Authenticate using an EIP-1193 / ethers-compatible wallet signer. */
  loginWithWallet: (
    wallet: {
      getAddress: () => Promise<string>;
      signMessage: (message: string) => Promise<string>;
    },
    chainId: number,
  ) => Promise<UserDialer>;
  /** Authenticate using a Solana wallet adapter. */
  loginWithSolana: (wallet: {
    publicKey: { toBase58: () => string };
    signMessage: (message: Uint8Array) => Promise<Uint8Array>;
  }) => Promise<UserDialer>;
  /** Logout and clear the authenticated session. */
  logout: () => Promise<void>;
  /** The current session data, or null if unauthenticated. */
  session: SessionData | null;
  /** Whether the user is currently authenticated. */
  isAuthenticated: boolean;
  /** Whether a login or logout operation is in progress. */
  isLoading: boolean;
}

/**
 * Manage authentication state for the Dial SDK.
 *
 * @throws Error if used outside of a DialProvider.
 *
 * @example
 * ```tsx
 * const { login, logout, isAuthenticated, session } = useAuth();
 *
 * // Login with SIWE
 * await login({ siwe: { message, signature } });
 *
 * // Or with a wallet
 * await loginWithWallet(signer, 1);
 * ```
 */
export function useAuth(): UseAuthReturn {
  const client = useContext(DialClientContext);
  const userDialerCtx = useContext(UserDialerContext);

  if (!client || !userDialerCtx) {
    throw new Error(
      'useAuth must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  const { userDialer, setUserDialer } = userDialerCtx;
  const [isLoading, setIsLoading] = useState(false);

  const login = useCallback(
    async (credentials: AuthCredentials): Promise<UserDialer> => {
      setIsLoading(true);
      try {
        const ud = await client.asUser(credentials);
        setUserDialer(ud);
        return ud;
      } finally {
        setIsLoading(false);
      }
    },
    [client, setUserDialer],
  );

  const loginWithWallet = useCallback(
    async (
      wallet: {
        getAddress: () => Promise<string>;
        signMessage: (message: string) => Promise<string>;
      },
      chainId: number,
    ): Promise<UserDialer> => {
      setIsLoading(true);
      try {
        const ud = await client.authenticateWithWallet({ wallet, chainId });
        setUserDialer(ud);
        return ud;
      } finally {
        setIsLoading(false);
      }
    },
    [client, setUserDialer],
  );

  const loginWithSolana = useCallback(
    async (wallet: {
      publicKey: { toBase58: () => string };
      signMessage: (message: Uint8Array) => Promise<Uint8Array>;
    }): Promise<UserDialer> => {
      setIsLoading(true);
      try {
        const ud = await client.authenticateWithSolana({ wallet });
        setUserDialer(ud);
        return ud;
      } finally {
        setIsLoading(false);
      }
    },
    [client, setUserDialer],
  );

  const logout = useCallback(async (): Promise<void> => {
    if (!userDialer) return;
    setIsLoading(true);
    try {
      await userDialer.logout();
      setUserDialer(null);
    } finally {
      setIsLoading(false);
    }
  }, [userDialer, setUserDialer]);

  const session: SessionData | null = useMemo(
    () => (userDialer ? userDialer.exportSession() : null),
    [userDialer],
  );

  const isAuthenticated = userDialer !== null;

  return { login, loginWithWallet, loginWithSolana, logout, session, isAuthenticated, isLoading };
}
