/**
 * @file use-conference.ts
 * @description Hook to access the ConferenceService from the authenticated UserDialer.
 * @layer React Hooks
 */

'use client';

import { useContext } from 'react';
import type { ConferenceService } from '@dial-wtf/client';
import { UserDialerContext } from '../context';

/**
 * Access the conference service for video conferencing and room management.
 *
 * @throws Error if used outside of a DialProvider.
 * @throws Error if the user is not authenticated.
 *
 * @example
 * ```tsx
 * const conference = useConference();
 * const room = await conference.create({ name: 'Standup', maxParticipants: 10 });
 * ```
 */
export function useConference(): ConferenceService {
  const ctx = useContext(UserDialerContext);

  if (!ctx) {
    throw new Error(
      'useConference must be used within a <DialProvider>. ' +
      'Wrap your component tree with <DialProvider> to provide the Dial SDK context.',
    );
  }

  if (!ctx.userDialer) {
    throw new Error(
      'useConference requires an authenticated session. ' +
      'Call login() via useAuth() before using this hook.',
    );
  }

  return ctx.userDialer.conference;
}
